mapper.select:
SELECT a.created_date,a.feedback_content,a.feedback_id,a.parents_id, b.REAL_NAME as toUserName,c.REAL_NAME as USERNAME,a.feedback_type as type FROM `publish_feedback_management` a LEFT JOIN sys_user b ON a.to_user_id = b.USER_ID LEFT JOIN sys_user c ON a.CREATED_BY = c.USER_ID where a.deleted = 0 and a.feedback_id in
#{id}
or a.parents_id in
#{id}
order BY a.created_date desc

SELECT a.created_date,a.feedback_content,a.feedback_id,a.parents_id,a.reply_status, b.REAL_NAME as toUserName,b.USER_ID as to_user_id,b.USER_PIC_DATA as to_user_img_url, c.REAL_NAME as USERNAME,c.USER_ID as createdBy,c.USER_PIC_DATA as user_img_url, a.feedback_type FROM `publish_feedback_management` a LEFT JOIN sys_user b ON a.to_user_id = b.USER_ID LEFT JOIN sys_user c ON a.CREATED_BY = c.USER_ID WHERE a.deleted = 0
AND a.reply_status = #{replyStatus}
AND a.created_by = #{userId}
AND a.parents_id = #{parentsId}
AND a.last_updated_date >= #{startTime}
AND a.last_updated_date <= #{endTime}
AND (a.feedback_content like concat('%', #{queryInfo}, '%') or a.feedback_type like concat('%', #{queryInfo}, '%') or c.REAL_NAME like concat('%', #{queryInfo}, '%'))
order by a.last_updated_date desc
